function SearchPeopleValid(n){var r,u;console.log("valid",n);var f=$(n),t=f.data("guid"),i=$("#"+t+"-list").children();$("#"+t+"-visible").is(":focus")||$("#"+t+"-suggestion").addClass("d-none");r=!0;u=0;for(let t=0;t<i.length;t++)if($(n).val().toUpperCase()==$(i[t]).text().toUpperCase()){r=!1;u=$(i[t]).data("id");break}r==!0?($(n).val(""),$("#"+t+"-hidden").val("")):$("#"+t+"-hidden").val(u);n.value==""&&i.each(function(n){i[n].style.display=""})}function personselector(n){var t=$(n),r=t.data("id"),i=$(t).parent().attr("id").replace("-list","");$("#"+i+"-visible").val(t.text().trim());$("#"+i+"-hidden").val(r);$("#"+i+"-suggestion").addClass("d-none")}function SearchPeopleSuggestion(n){var i=n.getAttribute("data-guid"),r=n.value.toUpperCase(),t=$("#"+i+"-list").children();t.each(function(n){t[n].style.display=$(this).text().toUpperCase().includes(r)?"":"none"})}$(function(){$("body").on("click",".person-select",function(n){var t=n.target,i=t.getAttribute("data-guid"),r;$("#"+i+"-suggestion").removeClass("d-none");r=$(t).parent();$(document).on("click",function(n){var t=$(n.target);t.closest(r).length||$("#"+i+"-suggestion").addClass("d-none")});t.addEventListener("keyup",n=>{n.key==="Escape"?(SearchPeopleValid(t),$("#"+i+"-suggestion").addClass("d-none")):SearchPeopleSuggestion(t)})})});